// List<T> usa um array interno com capacidade dinâmica
var list = new List<int> { 10, 20, 30 };
list.Add(40);          // append amortizado O(1)
list.Insert(1, 15);    // desloca elementos
list[2] = 99;          // acesso por índice O(1)

codeSnippets.javascript:
// Arrays em JS funcionam como listas dinâmicas
const list = [10, 20, 30];
list.push(40);        // append amortizado O(1)
list.splice(1, 0, 15);
list[2] = 99;
